package com.cognizant.springmockito;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;import java.util.Optional;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;@ExtendWith(MockitoExtension.class) public class UserServiceTest {@Mock UserRepository userRepository;@InjectMocks UserService userService;@Test void testGetUser(){when(userRepository.findById(1L)).thenReturn(Optional.of(new User(1L,"Aman")));User result=userService.getUserById(1L);assertNotNull(result);assertEquals(1L,result.getId());assertEquals("Aman",result.getName());verify(userRepository).findById(1L);}}
